import React from "react";
import { toast } from "react-toastify";
import {
  doc,
  getDocs,
  increment,
  query,
  updateDoc,
  where,
  addDoc,
  collection,
  getDoc,
  orderBy,
  limit,
  startAfter,
} from "firebase/firestore/lite";
const { formatISO } = require("date-fns");

export const collectionKeys = {
  BLOG: process.env.GATSBY_COL_BLOG,
  CAREER: process.env.GATSBY_APP_COL_CAREER,
  CLIENTS: process.env.GATSBY_APP_COL_CLIENTS,
  META: process.env.GATSBY_APP_COL_META,
  VIEWCOUNT: process.env.GATSBY_APP_COL_VIEW_COUNT,
  REFERAL: process.env.GATSBY_APP_COL_REFERAL,
};

export const addCount = async (db, key) => {
  try {
    const clients = collection(db, collectionKeys.VIEWCOUNT);
    await addDoc(clients, {
      count: 1,
      key: key,
      lastUpdate: formatISO(new Date()),
    });
  } catch (err) {
    console.error("err add::", err);
  }
};

export const getDocData = async (db, path) => {
  try {
    if (db) {
      const querySnapshot = await getDocs(collection(db, path));
      const data = querySnapshot.docs.map((doc) => ({
        id: doc.id, // Each document id
        ...doc.data(), // Spread the document data
      }));
      return data;
    }
  } catch (err) {
    console.error(`err getDoc`, err);
  }
};

export const getDocsFirebase = async (db, key) => {
  try {
    const q = query(
      collection(db, collectionKeys.VIEWCOUNT),
      where("key", "==", key),
    );
    const querySnapshot = await getDocs(q);
    return querySnapshot;
  } catch (err) {
    console.error(`err getDoc`, err);
  }
};

export const updateFirebaseCount = async (docId, db, key) => {
  try {
    const docRef = doc(db, collectionKeys.VIEWCOUNT, docId);
    await updateDoc(docRef, {
      count: increment(1),
      lastUpdate: formatISO(new Date()),
    });
    let querySnapshot = await getDocsFirebase(db, key);
    let count;
    querySnapshot?.docs?.forEach(async (doc) => {
      count = doc.data();
    });
    return count;
  } catch (e) {
    console.error("Error updating document: ", e);
  }
};

export const getDocDataFilter = async (db, path, key, value) => {
  const queryData = await query(collection(db, path), where(key, "==", value));
  const querySnapshot = await getDocs(queryData);
  const data = querySnapshot.docs.map((doc) => ({
    id: doc.id,
    ...doc.data(),
  }));
  return data;
};

export const getDocDetails = async (db, collectionName, id) => {
  const docRef = await doc(db, collectionName, id);
  const docSnap = await getDoc(docRef);
  if (docSnap.exists()) {
    return docSnap.data();
  }
  return;
};

export const fetchPaginatedData = async (
  db,
  collectionName,
  orderByField = "createdAt",
  limitCount = 10,
  lastVisibleDoc = null,
) => {
  try {
    const dataRef = collection(db, collectionName);
    let q = query(dataRef, orderBy(orderByField, "desc"), limit(limitCount));

    if (lastVisibleDoc) {
      q = query(
        dataRef,
        orderBy(orderByField, "desc"),
        startAfter(lastVisibleDoc),
        limit(limitCount),
      );
    }

    const documentSnapshots = await getDocs(q);
    const lastVisible =
      documentSnapshots.docs[documentSnapshots.docs.length - 1];

    return {
      data: documentSnapshots.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
      })),
      lastVisible,
      hasMore: documentSnapshots.size === limitCount,
    };
  } catch (error) {
    console.error("Error fetching paginated data:", error);
    return { data: [], lastVisible: null, hasMore: false };
  }
};

